fn solve(weight: Vec<i64>) -> i64 {
    let n = weight.len();
    if n < 2 {
        return 0;
    }

    let mut res = 0;
    let mut i = 0;
    while i < n {
        let mut max_val = weight[i];
        let mut last_val = weight[i];
        let mut j = i + 1;
        let mut found = false;
        while j < n {
            if weight[j] > max_val {
                max_val = weight[j];
            }
            last_val = weight[j];
            if last_val < max_val {
                res += 1;
                i = j + 1;
                found = true;
                break;
            }
            j += 1;
        }
        if !found {
            i += 1;
        }
    }
    res
}
